INSERT INTO agent_knowledge (content, summary, agent, category, confidence, source, created_by) VALUES
('LEAD_SCORING_MODEL: Le scoring basique: ouverture email=1pt, clic=3pts, visite pricing=5pts, demo request=10pts, formulaire=8pts.', 'Lead scoring: email 1pt, clic 3, pricing 5, demo 10, form 8', 'commercial', 'best_practice', 0.85, 'massive_boost_37', 'system'),
('LEAD_SCORING_MODEL: Le firmographic scoring: taille entreprise adaptee=5pts, industrie ciblee=5pts, budget confirme=10pts.', 'Firmographic scoring: taille 5, industrie 5, budget 10', 'commercial', 'best_practice', 0.82, 'massive_boost_37', 'system'),
('LEAD_SCORING_MODEL: Le behavior scoring decay: reduire le score de 10% par semaine d inactivite pour garder le scoring actuel.', 'Scoring decay: -10%/semaine inactivite', 'commercial', 'best_practice', 0.80, 'massive_boost_37', 'system'),
('LEAD_SCORING_MODEL: Le seuil de passage MQL→SQL: score > 50 et au moins 1 interaction dans les 7 derniers jours.', 'MQL→SQL: score >50 + interaction <7j', 'commercial', 'best_practice', 0.82, 'massive_boost_37', 'system'),
('LEAD_SCORING_MODEL: Le negative scoring: desinscription=-20pts, bounced email=-15pts, concurrent identifie=-50pts.', 'Negative scoring: desinscrip -20, bounce -15, concurrent -50', 'commercial', 'best_practice', 0.82, 'massive_boost_37', 'system'),
('OUTREACH_CADENCE: La cadence multicanale ideale sur 14 jours: J1 email, J3 LinkedIn, J5 email, J7 call, J10 email, J14 breakup.', 'Cadence 14j: J1 email, J3 LI, J5 email, J7 call, J10 email, J14 breakup', 'commercial', 'best_practice', 0.82, 'massive_boost_37', 'system'),
('OUTREACH_CADENCE: Le touchpoint #5 a le meilleur taux de reponse (18%). La majorite abandonne apres le 2e.', 'Touchpoint #5 = 18% reponse. Majorite abandonne apres #2', 'commercial', 'insight', 0.82, 'massive_boost_37', 'system'),
('OUTREACH_CADENCE: L email de rupture (breakup email) a paradoxalement le 2e meilleur taux de reponse de la sequence.', 'Breakup email = 2e meilleur taux reponse sequence', 'email', 'insight', 0.80, 'massive_boost_37', 'system'),
('OUTREACH_CADENCE: Le delai entre les touchpoints doit augmenter: J1→J3=2j, J3→J5=2j, J5→J7=2j, J7→J10=3j, J10→J14=4j.', 'Delai touchpoints croissant: 2j, 2j, 2j, 3j, 4j', 'commercial', 'best_practice', 0.80, 'massive_boost_37', 'system'),
('OUTREACH_CADENCE: Le weekend send (dimanche soir 20h) pour les cold emails a un taux d ouverture surprenamment eleve (28%).', 'Cold email dimanche 20h = 28% ouverture (surprise)', 'email', 'insight', 0.75, 'massive_boost_37', 'system'),
('VIDEO_ADS: Les video ads de 6 secondes (bumper ads) sur YouTube ont un taux de rappel de 90%.', 'Bumper ads 6s YouTube = 90% rappel', 'ads', 'insight', 0.82, 'massive_boost_37', 'system'),
('VIDEO_ADS: Le hook visuel dans les 2 premieres secondes est obligatoire car l utilisateur peut skipper a 5s.', 'Video ads hook 2s obligatoire (skip a 5s)', 'ads', 'best_practice', 0.88, 'massive_boost_37', 'system'),
('VIDEO_ADS: Les video ads avec temoignage client convertissent 2x mieux que les videos corporate.', 'Video ads temoignage client = 2x conversion vs corporate', 'ads', 'insight', 0.85, 'massive_boost_37', 'system'),
('VIDEO_ADS: Le cost per view (CPV) YouTube moyen: 0.01-0.05€. Tres rentable pour le branding.', 'YouTube CPV moyen: 0.01-0.05€ = rentable branding', 'ads', 'insight', 0.80, 'massive_boost_37', 'system'),
